import React, { useState } from "react";
import { createClient } from "@supabase/supabase-js";
import styled, { keyframes } from "styled-components";
import { motion } from "framer-motion";

/**
 * Packages to install:
 *   npm i styled-components framer-motion @supabase/supabase-js
 *
 * Environment:
 *   REACT_APP_SUPABASE_URL=
 *   REACT_APP_SUPABASE_KEY=
 */

const supabase = createClient(
    process.env.REACT_APP_SUPABASE_URL,
    process.env.REACT_APP_SUPABASE_KEY
);

export default function Login({ onLoginSuccess }) {
    const [email, setEmail] = useState("");
    const [password, setPassword] = useState("");
    const [loading, setLoading] = useState(false);
    const [error, setError] = useState("");
    const [showPassword, setShowPassword] = useState(false);

    const handleLogin = async (e) => {
        e.preventDefault();
        setError("");
        setLoading(true);

        try {
            const { data, error } = await supabase
                .from("Login")
                .select("*")
                .eq("kullanici_adi", email)
                .eq("sifre", password)
                .single();

            if (error || !data) {
                setError("Hatalı kullanıcı adı veya şifre.");
                return;
            }

            // ⚠️ Not: Düz şifre saklamak güvenli değildir. Supabase Auth kullanmanız önerilir.
            localStorage.setItem("kullanici", JSON.stringify(data));

            const reelUser =
                data.Reel_kullanici ??
                data.reel_kullanici ??
                data.reelUserName ??
                data.reel_username ??
                "";
            const reelPass =
                data.Reel_sifre ??
                data.reel_sifre ??
                data.reelPassword ??
                data.reel_password ??
                "";

            if (reelUser) localStorage.setItem("Reel_kullanici", reelUser);
            if (reelPass) localStorage.setItem("Reel_sifre", reelPass);

            if (reelUser && reelPass) {
                localStorage.setItem(
                    "reelCreds",
                    JSON.stringify({ userName: reelUser, password: reelPass })
                );
            } else {
                // eslint-disable-next-line no-console
                console.warn(
                    "[REEL] Giriş kaydında Reel_kullanici / Reel_sifre alanları bulunamadı."
                );
            }

            onLoginSuccess?.();
        } catch (err) {
            // eslint-disable-next-line no-console
            console.error(err);
            setError("Beklenmeyen bir hata oluştu. Lütfen tekrar deneyin.");
        } finally {
            setLoading(false);
        }
    };

    return (
        <Wrapper>
            <AnimatedBg aria-hidden />

            <Card
                as={motion.section}
                initial={{ opacity: 0, y: 20, filter: "blur(6px)" }}
                animate={{ opacity: 1, y: 0, filter: "blur(0px)" }}
                transition={{ duration: 0.6, ease: "easeOut" }}
            >
                <BrandRow>
                    <Logo>◆</Logo>
                    <Brand>Panel Giriş</Brand>
                </BrandRow>

                <Subtitle>Hesabınıza güvenle giriş yapın</Subtitle>

                <Form onSubmit={handleLogin} noValidate>
                    <Field>
                        <Label>Kullanıcı Adı</Label>
                        <Input
                            type="text"
                            placeholder="kullanici_adi"
                            value={email}
                            onChange={(e) => setEmail(e.target.value)}
                            autoComplete="username"
                            required
                        />
                    </Field>

                    <Field>
                        <Label>Şifre</Label>
                        <PasswordRow>
                            <Input
                                type={showPassword ? "text" : "password"}
                                placeholder="••••••••"
                                value={password}
                                onChange={(e) => setPassword(e.target.value)}
                                autoComplete="current-password"
                                required
                            />
                            <ShowBtn
                                type="button"
                                onClick={() => setShowPassword((s) => !s)}
                                aria-label={showPassword ? "Şifreyi gizle" : "Şifreyi göster"}
                            >
                                {showPassword ? "Gizle" : "Göster"}
                            </ShowBtn>
                        </PasswordRow>
                    </Field>

                    {error && <Error role="alert">{error}</Error>}

                    <Submit
                        type="submit"
                        disabled={loading || !email || !password}
                        as={motion.button}
                        whileTap={{ scale: 0.98 }}
                    >
                        {loading ? <Loader aria-label="Giriş yapılıyor" /> : "Giriş Yap"}
                    </Submit>

                    <HelperRow>
                        <Hint>Şifrenizi mi unuttunuz?</Hint>
                        <LinkButton type="button" onClick={() => alert("Destek ile iletişime geçin.")}>Destek</LinkButton>
                    </HelperRow>
                </Form>

                <Footer>
                    <Small>© {new Date().getFullYear()} Uygulamanız • Tüm hakları saklıdır</Small>
                </Footer>
            </Card>
        </Wrapper>
    );
}

/* ======================== Styled ======================== */
const float = keyframes`
  0% { transform: translateY(0px) }
  50% { transform: translateY(-10px) }
  100% { transform: translateY(0px) }
`;

const pulse = keyframes`
  0% { transform: scale(1); opacity: .9 }
  70% { transform: scale(1.05); opacity: 1 }
  100% { transform: scale(1); opacity: .9 }
`;

const shimmer = keyframes`
  0% { background-position: -200% 50%; }
  100% { background-position: 200% 50%; }
`;

const Wrapper = styled.main`
  min-height: 100dvh;
  display: grid;
  place-items: center;
  padding: 24px;
  background: radial-gradient(1200px 800px at 10% 10%, #0f172a 0%, #0b1020 40%, #070b19 100%);
  color: #e7eaff;
  overflow: hidden;
`;

const AnimatedBg = styled.div`
  position: absolute;
  inset: -10% -10% auto -10%;
  height: 120vh;
  background: conic-gradient(from 180deg at 50% 50%, #3b82f6, #8b5cf6, #06b6d4, #3b82f6);
  filter: blur(80px) saturate(1.2) opacity(.25);
  animation: ${pulse} 8s ease-in-out infinite;
  pointer-events: none;
`;

const Card = styled.div`
  position: relative;
  width: min(440px, 92vw);
  border-radius: 20px;
  padding: 28px 28px 18px;
  background: linear-gradient(180deg, rgba(255,255,255,.08), rgba(255,255,255,.04));
